import{_ as o,o as n,c as t,a3 as a}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"72. Payroll Deduction Of Union Dues","description":"","frontmatter":{"title":"72. Payroll Deduction Of Union Dues","eba":"Health Allied & Managers Admin 2021-2025","topics":["wages","union-matters"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/union-matters/72-payroll-deduction-of-union-dues.md","filePath":"ebas/has-managers-admin/common-terms/union-matters/72-payroll-deduction-of-union-dues.md"}'),r={name:"ebas/has-managers-admin/common-terms/union-matters/72-payroll-deduction-of-union-dues.md"};function s(i,e,d,m,l,u){return n(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="_72-payroll-deduction-of-union-dues" tabindex="-1">72. Payroll Deduction Of Union Dues <a class="header-anchor" href="#_72-payroll-deduction-of-union-dues" aria-label="Permalink to &quot;72. Payroll Deduction Of Union Dues&quot;">​</a></h1><p><strong>72.1</strong> On written request by an Employee, the Employer must deduct HWU membership dues from the Employee’s after tax wages. The Employee must indicate their category of HWU membership to determine the applicable amount of dues to be deducted. The Employee may change their nominated category of membership for the purpose of deductions once a year.</p><p><strong>72.2</strong> Monies collected will be forwarded to the HWU monthly together with all necessary information to enable the reconciliation of crediting of subscriptions to members&#39; accounts.</p><p><strong>72.3</strong> The HWU will inform the Employer and Employees who are members of the HWU of changes to the HWU membership dues when there is a change made in accordance with its rules.</p><p><strong>72.4</strong> An Employee may cease the deduction under this clause by notifying the Employer in writing.</p><p>Plain language terms: union fees, union deduction.</p>',6)])])}const h=o(r,[["render",s]]);export{p as __pageData,h as default};
